var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"헉… 허억…","JPN":"はっ……はあ……","ENG":"*Huff*… *Huff…*","TWN":"明達隊長。時機已成熟，我將要達到巔峰。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_115"},{"id":"L3_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"훈련을 받아도 몇 달째 제자리걸음이구나.","JPN":"ここ数か月訓練を重ねてきたが、成長はいまいちか。","ENG":"Even after months of training, you're still stuck in place.","TWN":"好。我會為你開路，你毫不猶豫地通過吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_OPR_DOGABI_IN_CUTSCENE_21"},{"id":"L5_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"전… 할 수… 있어요.","JPN":"私は……やれます。","ENG":"I… can still… do this.","TWN":"曾經觸及不到的雲霧，居然能挫敗本座的風浪。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_116"},{"id":"L6_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"이유도 없이 그저 악착같이 휘두르기만 하는 힘은 손잡이 없는 칼날과 다를 바 없다.","JPN":"理由もなくただがむしゃらに振るだけの力は、柄のない刃にすぎない。","ENG":"Strength used to swing blindly with no purpose is like a sword with no hilt.","TWN":"你這所謂的波羅蜜命刀…難道是在捨棄肉身之後，力量反而會變強嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_OPR_DOGABI_IN_CUTSCENE_22"},{"id":"L7_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그런 것으론 바라밀 명도를 완성시킬 수 없느니라.","JPN":"その程度では、波羅蜜命刀の完成に辿り着けないぞ。","ENG":"You'll never master the Sword of Paramita that way.","TWN":"你這傢伙只會利用人類的怨念，當然無法理解。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_OPR_DOGABI_IN_CUTSCENE_23"},{"id":"L8_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"하지만… 완성할 겁니다.","JPN":"それでも……やり遂げてみせます。","ENG":"Even so… I'll master it.","TWN":"一個不受任何事物束縛的女人，千年累積的怨恨…有多麼可怕。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_117"},{"id":"L9_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"반드시.","JPN":"必ず。","ENG":"No matter what.","TWN":"…真是可笑。再怎麼說也只是個人類而已。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_118"},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"그렇다면 말해보거라. 너에게 있어 이 힘을 필요로 하는 진짜 이유는 뭐지?","JPN":"なら言ってみろ。お前がこの力を欲する本当の理由はなんだ？","ENG":"Then tell me. What is the true reason you need that power?","TWN":"哈…哈啊…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_OPR_DOGABI_IN_CUTSCENE_24"},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"짐승에 대한 복수냐? 아니면 세상을 지킨다는 대의냐?","JPN":"ケモノへの復讐か？　それとも世界を守るという大儀か？","ENG":"Is it revenge against the Beast? Or to uphold some noble cause and protect the world?","TWN":"明明接受了訓練，卻好幾個月都在原地踏步。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_OPR_DOGABI_IN_CUTSCENE_25"},{"id":"L17_1","type":"narration","speaker":null,"text":{"KOREA":"지난 적엔 닿지도 못했을 터인 구름이 본좌의 풍랑을 꺾다니.","JPN":"かつては吾輩に到底届くことすら叶わなかった雲が、この風浪を叩くとは。","ENG":"A mere cloud, which couldn't even reach me before, now dares to quell my storm?","TWN":"我…可以…的。"},"stage":{"bg":"MS_1503","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BELL6"},{"id":"L18_1","type":"narration","speaker":null,"text":{"KOREA":"네놈의 바라밀 명도라는 것은… 육신을 버렸을 때 강해지기라도 한다는 말인가?","JPN":"貴様の波羅蜜命刀とは……肉体を放棄した際により強くなるとでもいうのか？","ENG":"Do you mean that your Sword of Paramita gets stronger when you abandon your physical body?","TWN":"沒有動機，只是一味地揮舞的力量，就像沒有刀柄的刀刃。"},"stage":{"bg":"MS_1503","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"지금껏 사람의 한을 부리기만 한 네놈은 모를 법도 하구나.","JPN":"人の恨みや無念を利用してきただけのお前には分かるまい。","ENG":"You've only ever manipulated the resentments of others. No wonder you don't understand.","TWN":"那樣是無法完成波羅蜜命刀的。"},"stage":{"bg":"MS_1503","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"어디에도 묶이지 않은 여인의 수천 년 묵은 한이… 얼마나 무서운지를 말이다.","JPN":"枷を壊し自由を手に入れた女の、数千年分の恨みがどれだけ恐ろしいか。","ENG":"Just how fearsome a woman's grudge spanning thousands of years can be, now that she is unbound.","TWN":"但是…我會完成的。"},"stage":{"bg":"MS_1503","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L23_1","type":"narration","speaker":null,"text":{"KOREA":"…가당찮구나. 그래보아야 한낱 인간인 것을.","JPN":"……おこがましいことよ。所詮はただの人間にすぎぬというのに。","ENG":"…Absurd. No matter what, still just a mere human.","TWN":"一定要。"},"stage":{"bg":"MS_1503","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_BELL6"},{"id":"L26_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"명달 대장. 때가 무르익었으니 정점을 찍겠습니다.","JPN":"アカタツ隊長、時が満ちました。ここで頂点を極めます。","ENG":"Commander Myeongdal. The time is ripe. I'm going in for the final strike.","TWN":"那麼說來聽聽。你真正需要這股力量的動機是什麼？"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_114"},{"id":"L28_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"오냐. 길을 터줄 테니 서슴지 말고 지나가거라.","JPN":"ああ。道は俺が開く。迷わず突き進め。","ENG":"Very well. I'll clear the way, so don't hesitate.","TWN":"是為了對野獸復仇嗎？還是守護世界的大義？"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_OPR_DOGABI_IN_CUTSCENE_20"},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"내가… 검을 쥔 이유는…","JPN":"私が……剣を握る理由は……","ENG":"The reason... I took up the sword is...","TWN":"我的…動機…"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_119"},{"id":"L33_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"소중한 사람을… 지키는 것.","JPN":"大切な人を……守るため。","ENG":"To protect… the one I love.","TWN":"是為了…守護重要的人。"},"stage":{"bg":"MS_1503","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_120"},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"바라밀 명도, 착호검","JPN":"波羅蜜命刀、捉虎剣。","ENG":"Sword of Paramita, Tigerbane.","TWN":"波羅蜜命刀，獵虎劍"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"제법무아 만상귀진 ","JPN":"諸法無我　萬法帰真","ENG":"There is no self in anything, and all phenomena come to an end. ","TWN":"諸法無我，萬象歸真。"},"stage":{"bg":"CLOSE","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};